import{_ as o,o as r,c as a,a2 as n}from"./chunks/framework.DGp-bpT-.js";const p=JSON.parse('{"title":"Управление организациями","description":"","frontmatter":{},"headers":[],"relativePath":"guide/organizations.md","filePath":"guide/organizations.md","lastUpdated":null}'),s={name:"guide/organizations.md"};function e(l,t,i,d,g,h){return r(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="управление-организациями" tabindex="-1">Управление организациями <a class="header-anchor" href="#управление-организациями" aria-label="Permalink to &quot;Управление организациями&quot;">​</a></h1><p>SREBot поддерживает <strong>мультиорганизационную модель</strong>: один пользователь может состоять в нескольких организациях с разными ролями в каждой. Это позволяет управлять инфраструктурой разных команд или проектов из единого аккаунта.</p><hr><h2 id="создание-организации" tabindex="-1">Создание организации <a class="header-anchor" href="#создание-организации" aria-label="Permalink to &quot;Создание организации&quot;">​</a></h2><p>После регистрации первая организация создаётся <strong>автоматически</strong> — пользователь сразу получает роль Владельца и может начать работу с платформой.</p><p>Чтобы создать <strong>дополнительную</strong> организацию:</p><ol><li>Нажмите на название текущей организации в верхней навигационной панели — откроется выпадающее меню.</li><li>Нажмите кнопку <strong>«+»</strong> (или перейдите напрямую на <code>/dashboard/organizations/new</code>).</li><li>Заполните форму: <ul><li><strong>Название организации</strong> — произвольное имя, которое будет отображаться в навигации.</li><li><strong>Язык / Регион</strong> — <code>RU</code> (Русский) или <code>EN</code> (English).</li></ul></li><li>Нажмите <strong>«Создать»</strong>.</li></ol><div class="info custom-block"><p class="custom-block-title">Валюта биллинга</p><p>Валюта определяется выбранным языком: <strong>Русский → RUB</strong>, <strong>English → USD</strong>. Валюта фиксируется при создании организации и <strong>не может быть изменена</strong> позже.</p></div><p>После создания вы автоматически станете <strong>Владельцем</strong> (Owner) новой организации и будете перенаправлены в её контекст.</p><hr><h2 id="членство-в-нескольких-организациях" tabindex="-1">Членство в нескольких организациях <a class="header-anchor" href="#членство-в-нескольких-организациях" aria-label="Permalink to &quot;Членство в нескольких организациях&quot;">​</a></h2><p>Пользователь может быть участником любого числа организаций, при этом роль в каждой из них назначается <strong>независимо</strong>.</p><p>Например, в одной организации вы можете быть Владельцем, а в другой — Наблюдателем.</p><p>Все организации, в которых вы состоите, отображаются в <strong>выпадающем списке навигационной панели</strong>. Каждая организация имеет собственное изолированное пространство:</p><ul><li><strong>Биллинг</strong> — отдельный баланс и история платежей.</li><li><strong>Токены ботов</strong> — агент-токены привязаны к конкретной организации.</li><li><strong>Команда</strong> — свой список участников и приглашений.</li><li><strong>Инциденты</strong> — данные инцидентов не пересекаются между организациями.</li></ul><hr><h2 id="переключение-между-организациями" tabindex="-1">Переключение между организациями <a class="header-anchor" href="#переключение-между-организациями" aria-label="Permalink to &quot;Переключение между организациями&quot;">​</a></h2><p>Для переключения между организациями не требуется повторная авторизация — достаточно выбрать нужную организацию из списка.</p><ol><li>Нажмите на <strong>название организации</strong> в верхней навигационной панели.</li><li>В выпадающем меню отобразятся все организации, в которых вы состоите. Текущая организация отмечена <strong>галочкой</strong> (✓).</li><li>Выберите нужную организацию — контекст дашборда обновится: инциденты, биллинг, команда и токены будут загружены для выбранной организации.</li><li>В нижней части выпадающего меню доступна кнопка <strong>«Создать организацию»</strong>.</li></ol><div class="tip custom-block"><p class="custom-block-title">Мгновенное переключение</p><p>Переключение происходит мгновенно — данные загружаются через API без перезагрузки страницы. Текущая сессия при этом не прерывается.</p></div><hr><h2 id="контекст-организации" tabindex="-1">Контекст организации <a class="header-anchor" href="#контекст-организации" aria-label="Permalink to &quot;Контекст организации&quot;">​</a></h2><p>Все данные и действия в дашборде привязаны к <strong>текущей организации</strong>. При переключении контекст полностью меняется:</p><table tabindex="0"><thead><tr><th>Раздел</th><th>Что входит в контекст</th></tr></thead><tbody><tr><td><strong>Инциденты</strong></td><td>Список инцидентов, детали анализа, история tool calls</td></tr><tr><td><strong>Биллинг</strong></td><td>Баланс, тариф, история транзакций, способы пополнения</td></tr><tr><td><strong>Команда</strong></td><td>Участники, роли, ожидающие приглашения</td></tr><tr><td><strong>Токены ботов</strong></td><td>Агент-токены для подключения к Telegram, Slack, Discord</td></tr></tbody></table><h3 id="роли-и-разрешения" tabindex="-1">Роли и разрешения <a class="header-anchor" href="#роли-и-разрешения" aria-label="Permalink to &quot;Роли и разрешения&quot;">​</a></h3><p>Ваши права доступа определяются <strong>членством в текущей организации</strong>. Если вы являетесь Владельцем в одной организации и Наблюдателем в другой, то при переключении на вторую вы получите только права Наблюдателя.</p><p>Подробнее о ролях читайте в разделе <a href="/docs/guide/team-management">Управление командой</a>.</p><h3 id="фиксированная-валюта" tabindex="-1">Фиксированная валюта <a class="header-anchor" href="#фиксированная-валюта" aria-label="Permalink to &quot;Фиксированная валюта&quot;">​</a></h3><p>Валюта биллинга устанавливается <strong>один раз</strong> при создании организации и не может быть изменена. Если вам нужна другая валюта, создайте новую организацию с нужным языком/регионом.</p>',29)])])}const u=o(s,[["render",e]]);export{p as __pageData,u as default};
